import { describe, expect, it } from 'vitest';

import {
  computeCommonTokens,
  getCommonTokensForToolList,
  type AgenticToolDefinition,
} from '../agentic-chat';

function tool(name: string, description: string): AgenticToolDefinition {
  return {
    type: 'function',
    function: { name, description },
  };
}

describe('computeCommonTokens', () => {
  it('flags a token appearing in most of the catalog and spares a rare one', () => {
    const tools: AgenticToolDefinition[] = [];
    for (let i = 0; i < 20; i += 1) {
      tools.push(tool(`gnosis/theorem_${i}`, 'Part of the MCP verification ledger.'));
    }
    tools.push(tool('network/search', 'Search the ForkJoin MCP superserver registry.'));

    const common = computeCommonTokens(tools);
    expect(common.has('mcp')).toBe(true);
    expect(common.has('verification')).toBe(true);
    expect(common.has('ledger')).toBe(true);
    // "search" and "registry" only appear on the one distinctive tool.
    expect(common.has('search')).toBe(false);
    expect(common.has('registry')).toBe(false);
  });

  it('flags nothing when no token clears the ratio', () => {
    const tools: AgenticToolDefinition[] = [
      tool('local/list_directory', 'Enumerate directory entries.'),
      tool('gnit/commit_changes', 'Record a version control snapshot.'),
      tool('network/search', 'Search the tool registry.'),
    ];
    const common = computeCommonTokens(tools, 0.5);
    expect(common.size).toBe(0);
  });
});

describe('getCommonTokensForToolList', () => {
  it('memoizes by array reference, returning the identical Set instance', () => {
    const tools: AgenticToolDefinition[] = [
      tool('gnosis/theorem_a', 'MCP verification ledger entry.'),
      tool('network/search', 'Search the registry.'),
    ];
    const first = getCommonTokensForToolList(tools);
    const second = getCommonTokensForToolList(tools);
    expect(second).toBe(first);
  });

  it('computes fresh for a different array reference, even with identical contents', () => {
    const toolsA: AgenticToolDefinition[] = [
      tool('gnosis/theorem_a', 'MCP verification ledger entry.'),
    ];
    const toolsB: AgenticToolDefinition[] = [
      tool('gnosis/theorem_a', 'MCP verification ledger entry.'),
    ];
    const a = getCommonTokensForToolList(toolsA);
    const b = getCommonTokensForToolList(toolsB);
    expect(a).not.toBe(b);
    expect(a).toEqual(b);
  });
});
